#include <iostream>
using namespace std;
struct tik{
    int p,t;bool used;
}s[100005];
int head,tail,cnt;
int main(){
    int n,w,m,sh;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>w>>m>>sh;
        if(w==0){
            s[tail].used=true;
            s[tail].p=m;s[tail++].t=sh+45;
            cnt+=m;
        }
        else{
            while(head<tail && sh>s[head].t)
                head++;
            bool flag=true;
            for(int i=head;i<tail;i++){
                if(s[i].p>=m && s[i].used){
                    flag=false;
                    s[i].used=false;
                    break;
                }
            }
            if(flag)cnt+=m;
        }
    }
    cout<<cnt;
    return 0;
}
